package com.dao;

import com.database.DatabaseInitializer;
import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.util.ArrayList;
import java.util.List;

/**
 * Abstract base class for all DAOs
 * Demonstrates: Abstract Class, Inheritance, Generics, Template Method Pattern
 */
public abstract class BaseDAO<T> implements IBaseDAO<T> {

    /**
     * Template method for getting count
     */
    @Override
    public int getCount() {
        String sql = "SELECT COUNT(*) FROM " + getTableName();
        try (Connection conn = DatabaseInitializer.getConnection();
             PreparedStatement pst = conn.prepareStatement(sql);
             ResultSet rs = pst.executeQuery()) {
            if (rs.next()) {
                return rs.getInt(1);
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
        return 0;
    }

    /**
     * Abstract method - subclasses must implement
     */
    protected abstract String getTableName();

    /**
     * Abstract method - subclasses must implement
     */
    @Override
    public abstract T getById(Object id);

    /**
     * Abstract method - subclasses must implement
     */
    @Override
    public abstract List<T> getAll();

    /**
     * Abstract method - subclasses must implement
     */
    @Override
    public abstract boolean save(T entity);

    /**
     * Abstract method - subclasses must implement
     */
    @Override
    public abstract boolean update(T entity);

    /**
     * Abstract method - subclasses must implement
     */
    @Override
    public abstract boolean delete(Object id);

    /**
     * Helper method to safely close resources
     */
    protected void closeResources(Connection conn, PreparedStatement pst, ResultSet rs) {
        try {
            if (rs != null) rs.close();
            if (pst != null) pst.close();
            if (conn != null) conn.close();
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

package com.dao;

import java.util.List;

/**
 * Generic DAO Interface
 * Demonstrates: Interface, Abstraction
 * Defines contract for all DAO implementations
 */
public interface IBaseDAO<T> {

    /**
     * Get an entity by ID
     */
    T getById(Object id);

    /**
     * Get all entities
     */
    List<T> getAll();

    /**
     * Save/Insert an entity
     */
    boolean save(T entity);

    /**
     * Update an entity
     */
    boolean update(T entity);

    /**
     * Delete an entity by ID
     */
    boolean delete(Object id);

    /**
     * Get count of all entities
     */
    int getCount();
}

package com.dao.notes;

import com.database.DatabaseInitializer;
import com.model.notes.CourseAnnouncement;
import com.model.notes.CourseMaterial;

import java.io.File;
import java.io.FileInputStream;
import java.sql.*;
import java.util.ArrayList;
import java.util.List;

public class CourseContentDAO {

    public CourseContentDAO() {
        createTables();
    }

    private void createTables() {
        String materials = """
            CREATE TABLE IF NOT EXISTS course_materials (
                id INT PRIMARY KEY AUTO_INCREMENT,
                course_id VARCHAR(50) NOT NULL,
                week_no INT NOT NULL,
                title VARCHAR(150) NOT NULL,
                file_name VARCHAR(255) NOT NULL,
                pdf_file LONGBLOB NOT NULL,
                uploaded_by VARCHAR(100) NOT NULL,
                uploaded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        """;

        String announcements = """
            CREATE TABLE IF NOT EXISTS course_announcements (
                id INT PRIMARY KEY AUTO_INCREMENT,
                course_id VARCHAR(50) NOT NULL,
                week_no INT NOT NULL,
                announcement_text TEXT NOT NULL,
                created_by VARCHAR(100) NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        """;

        try (Connection con = DatabaseInitializer.getConnection();
             Statement st = con.createStatement()) {
            st.execute(materials);
            st.execute(announcements);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    public boolean uploadPdf(String courseId, int weekNo, String title, File pdfFile, String lecturerId) {
        String sql = """
            INSERT INTO course_materials
            (course_id, week_no, title, file_name, pdf_file, uploaded_by)
            VALUES (?, ?, ?, ?, ?, ?)
        """;

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql);
             FileInputStream fis = new FileInputStream(pdfFile)) {

            ps.setString(1, courseId);
            ps.setInt(2, weekNo);
            ps.setString(3, title);
            ps.setString(4, pdfFile.getName());
            ps.setBinaryStream(5, fis, pdfFile.length());
            ps.setString(6, lecturerId);

            return ps.executeUpdate() > 0;

        } catch (Exception e) {
            e.printStackTrace();
            return false;
        }
    }

    public boolean addAnnouncement(String courseId, int weekNo, String text, String lecturerId) {
        String sql = """
            INSERT INTO course_announcements
            (course_id, week_no, announcement_text, created_by)
            VALUES (?, ?, ?, ?)
        """;

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql)) {

            ps.setString(1, courseId);
            ps.setInt(2, weekNo);
            ps.setString(3, text);
            ps.setString(4, lecturerId);

            return ps.executeUpdate() > 0;

        } catch (Exception e) {
            e.printStackTrace();
            return false;
        }
    }

    public List<CourseMaterial> getMaterials(String courseId, int weekNo) {
        List<CourseMaterial> list = new ArrayList<>();

        String sql = """
            SELECT id, course_id, week_no, title, file_name, uploaded_by,
                   DATE_FORMAT(uploaded_at, '%Y-%m-%d %H:%i') AS uploaded_at
            FROM course_materials
            WHERE course_id = ? AND week_no = ?
            ORDER BY uploaded_at DESC
        """;

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql)) {

            ps.setString(1, courseId);
            ps.setInt(2, weekNo);

            ResultSet rs = ps.executeQuery();

            while (rs.next()) {
                list.add(new CourseMaterial(
                        rs.getInt("id"),
                        rs.getString("course_id"),
                        rs.getInt("week_no"),
                        rs.getString("title"),
                        rs.getString("file_name"),
                        rs.getString("uploaded_by"),
                        rs.getString("uploaded_at")
                ));
            }

        } catch (Exception e) {
            e.printStackTrace();
        }

        return list;
    }

    public List<CourseAnnouncement> getAnnouncements(String courseId, int weekNo) {
        List<CourseAnnouncement> list = new ArrayList<>();

        String sql = """
            SELECT id, course_id, week_no, announcement_text, created_by,
                   DATE_FORMAT(created_at, '%Y-%m-%d %H:%i') AS created_at
            FROM course_announcements
            WHERE course_id = ? AND week_no = ?
            ORDER BY created_at DESC
        """;

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql)) {

            ps.setString(1, courseId);
            ps.setInt(2, weekNo);

            ResultSet rs = ps.executeQuery();

            while (rs.next()) {
                list.add(new CourseAnnouncement(
                        rs.getInt("id"),
                        rs.getString("course_id"),
                        rs.getInt("week_no"),
                        rs.getString("announcement_text"),
                        rs.getString("created_by"),
                        rs.getString("created_at")
                ));
            }

        } catch (Exception e) {
            e.printStackTrace();
        }

        return list;
    }

    public byte[] getPdfFile(int materialId) {
        String sql = "SELECT pdf_file FROM course_materials WHERE id = ?";

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql)) {

            ps.setInt(1, materialId);

            ResultSet rs = ps.executeQuery();

            if (rs.next()) {
                return rs.getBytes("pdf_file");
            }

        } catch (Exception e) {
            e.printStackTrace();
        }

        return null;
    }

    public String getPdfFileName(int materialId) {
        String sql = "SELECT file_name FROM course_materials WHERE id = ?";

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql)) {

            ps.setInt(1, materialId);

            ResultSet rs = ps.executeQuery();

            if (rs.next()) {
                return rs.getString("file_name");
            }

        } catch (Exception e) {
            e.printStackTrace();
        }

        return "lecture_note.pdf";
    }

    public boolean deleteMaterial(int id, String lecturerId) {
        String sql = "DELETE FROM course_materials WHERE id = ? AND uploaded_by = ?";

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql)) {

            ps.setInt(1, id);
            ps.setString(2, lecturerId);

            return ps.executeUpdate() > 0;

        } catch (Exception e) {
            e.printStackTrace();
            return false;
        }
    }

    public boolean deleteAnnouncement(int id, String lecturerId) {
        String sql = "DELETE FROM course_announcements WHERE id = ? AND created_by = ?";

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql)) {

            ps.setInt(1, id);
            ps.setString(2, lecturerId);

            return ps.executeUpdate() > 0;

        } catch (Exception e) {
            e.printStackTrace();
            return false;
        }
    }
}

package com.dao.notes;

import com.database.DatabaseInitializer;
import com.model.admin.Course;
import com.model.notes.CourseAnnouncement;
import com.model.notes.CourseMaterial;

import java.io.File;
import java.io.FileInputStream;
import java.sql.*;
import java.util.ArrayList;
import java.util.List;

public class CourseContentDAO {

    public CourseContentDAO() {
        createTables();
    }

    private void createTables() {
        String materials = """
            CREATE TABLE IF NOT EXISTS course_materials (
                id INT PRIMARY KEY AUTO_INCREMENT,
                course_id VARCHAR(50) NOT NULL,
                week_no INT NOT NULL,
                title VARCHAR(150) NOT NULL,
                file_name VARCHAR(255) NOT NULL,
                pdf_file LONGBLOB NOT NULL,
                uploaded_by VARCHAR(100) NOT NULL,
                uploaded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        """;

        String announcements = """
            CREATE TABLE IF NOT EXISTS course_announcements (
                id INT PRIMARY KEY AUTO_INCREMENT,
                course_id VARCHAR(50) NOT NULL,
                week_no INT NOT NULL,
                announcement_text TEXT NOT NULL,
                created_by VARCHAR(100) NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        """;

        try (Connection con = DatabaseInitializer.getConnection();
             Statement st = con.createStatement()) {
            st.execute(materials);
            st.execute(announcements);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    public boolean uploadPdf(String courseId, int weekNo, String title, File pdfFile, String lecturerId) {
        String sql = """
            INSERT INTO course_materials
            (course_id, week_no, title, file_name, pdf_file, uploaded_by)
            VALUES (?, ?, ?, ?, ?, ?)
        """;

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql);
             FileInputStream fis = new FileInputStream(pdfFile)) {

            ps.setString(1, courseId);
            ps.setInt(2, weekNo);
            ps.setString(3, title);
            ps.setString(4, pdfFile.getName());
            ps.setBinaryStream(5, fis, pdfFile.length());
            ps.setString(6, lecturerId);

            return ps.executeUpdate() > 0;

        } catch (Exception e) {
            e.printStackTrace();
            return false;
        }
    }

    public boolean addAnnouncement(String courseId, int weekNo, String text, String lecturerId) {
        String sql = """
            INSERT INTO course_announcements
            (course_id, week_no, announcement_text, created_by)
            VALUES (?, ?, ?, ?)
        """;

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql)) {

            ps.setString(1, courseId);
            ps.setInt(2, weekNo);
            ps.setString(3, text);
            ps.setString(4, lecturerId);

            return ps.executeUpdate() > 0;

        } catch (Exception e) {
            e.printStackTrace();
            return false;
        }
    }

    public List<CourseMaterial> getMaterials(String courseId, int weekNo) {
        List<CourseMaterial> list = new ArrayList<>();

        String sql = """
            SELECT id, course_id, week_no, title, file_name, uploaded_by,
                   DATE_FORMAT(uploaded_at, '%Y-%m-%d %H:%i') AS uploaded_at
            FROM course_materials
            WHERE course_id = ? AND week_no = ?
            ORDER BY uploaded_at DESC
        """;

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql)) {

            ps.setString(1, courseId);
            ps.setInt(2, weekNo);

            ResultSet rs = ps.executeQuery();

            while (rs.next()) {
                list.add(new CourseMaterial(
                        rs.getInt("id"),
                        rs.getString("course_id"),
                        rs.getInt("week_no"),
                        rs.getString("title"),
                        rs.getString("file_name"),
                        rs.getString("uploaded_by"),
                        rs.getString("uploaded_at")
                ));
            }

        } catch (Exception e) {
            e.printStackTrace();
        }

        return list;
    }

    public List<CourseAnnouncement> getAnnouncements(String courseId, int weekNo) {
        List<CourseAnnouncement> list = new ArrayList<>();

        String sql = """
            SELECT id, course_id, week_no, announcement_text, created_by,
                   DATE_FORMAT(created_at, '%Y-%m-%d %H:%i') AS created_at
            FROM course_announcements
            WHERE course_id = ? AND week_no = ?
            ORDER BY created_at DESC
        """;

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql)) {

            ps.setString(1, courseId);
            ps.setInt(2, weekNo);

            ResultSet rs = ps.executeQuery();

            while (rs.next()) {
                list.add(new CourseAnnouncement(
                        rs.getInt("id"),
                        rs.getString("course_id"),
                        rs.getInt("week_no"),
                        rs.getString("announcement_text"),
                        rs.getString("created_by"),
                        rs.getString("created_at")
                ));
            }

        } catch (Exception e) {
            e.printStackTrace();
        }

        return list;
    }

    public byte[] getPdfFile(int materialId) {
        String sql = "SELECT pdf_file FROM course_materials WHERE id = ?";

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql)) {

            ps.setInt(1, materialId);

            ResultSet rs = ps.executeQuery();

            if (rs.next()) {
                return rs.getBytes("pdf_file");
            }

        } catch (Exception e) {
            e.printStackTrace();
        }

        return null;
    }

    public String getPdfFileName(int materialId) {
        String sql = "SELECT file_name FROM course_materials WHERE id = ?";

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql)) {

            ps.setInt(1, materialId);

            ResultSet rs = ps.executeQuery();

            if (rs.next()) {
                return rs.getString("file_name");
            }

        } catch (Exception e) {
            e.printStackTrace();
        }

        return "lecture_note.pdf";
    }

    public boolean deleteMaterial(int id, String lecturerId) {
        String sql = "DELETE FROM course_materials WHERE id = ? AND uploaded_by = ?";

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql)) {

            ps.setInt(1, id);
            ps.setString(2, lecturerId);

            return ps.executeUpdate() > 0;

        } catch (Exception e) {
            e.printStackTrace();
            return false;
        }
    }

    public boolean deleteAnnouncement(int id, String lecturerId) {
        String sql = "DELETE FROM course_announcements WHERE id = ? AND created_by = ?";

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql)) {

            ps.setInt(1, id);
            ps.setString(2, lecturerId);

            return ps.executeUpdate() > 0;

        } catch (Exception e) {
            e.printStackTrace();
            return false;
        }
    }

    public List<Course> getStudentRegisteredCourses(String regNo) {
        List<Course> courses = new ArrayList<>();

        String sql = """
                SELECT c.id, c.department, c.year, c.semester, c.course_id, c.course_name,
                       c.coordinator, c.credits, c.image_path, c.status
                FROM course_registration cr
                JOIN courses c ON cr.course_id = c.course_id
                WHERE cr.reg_no = ?
                ORDER BY c.year, c.semester, c.course_name
                """;

        try (Connection con = DatabaseInitializer.getConnection();
             PreparedStatement ps = con.prepareStatement(sql)) {

            ps.setString(1, regNo);

            ResultSet rs = ps.executeQuery();

            while (rs.next()) {
                Course course = new Course(
                        rs.getString("department"),
                        rs.getString("year"),
                        rs.getString("semester"),
                        rs.getString("course_id"),
                        rs.getString("course_name"),
                        rs.getString("coordinator"),
                        rs.getInt("credits"),
                        rs.getString("image_path"),
                        rs.getString("status")
                );
                course.setId(rs.getInt("id"));
                courses.add(course);
            }

        } catch (Exception e) {
            e.printStackTrace();
        }

        return courses;
    }
}

package com.model;

import java.time.LocalDate;

/**
 * Abstract class representing an Employee
 * Extends Person and adds employee-specific properties
 * Demonstrates: Inheritance, Polymorphism
 */
public abstract class Employee extends Person {

    private String employeeId;
    private String department;
    private LocalDate appointmentDate;
    private String status;

    /**
     * Constructor for Employee
     */
    public Employee(String firstName, String lastName, String nic, LocalDate dateOfBirth,
                   String gender, String imagePath, String email, String phone,
                   String address, String district, String employeeId, String department,
                   LocalDate appointmentDate, String status) {
        super(firstName, lastName, nic, dateOfBirth, gender, imagePath, email, phone, address, district);
        this.employeeId = employeeId;
        this.department = department;
        this.appointmentDate = appointmentDate;
        this.status = status;
    }

    /**
     * No-argument constructor
     */
    public Employee() {
        super();
    }

    /**
     * Polymorphic method - returns employee-specific contact info
     */
    @Override
    public String getContactInfo() {
        return super.getContactInfo() + " | Emp ID: " + employeeId + " | Dept: " + department;
    }

    /**
     * Abstract method to be implemented by specific employee types
     */
    public abstract String getEmployeeType();

    // Getters and Setters
    public String getEmployeeId() {
        return employeeId;
    }

    public void setEmployeeId(String employeeId) {
        this.employeeId = employeeId;
    }

    public String getDepartment() {
        return department;
    }

    public void setDepartment(String department) {
        this.department = department;
    }

    public LocalDate getAppointmentDate() {
        return appointmentDate;
    }

    public void setAppointmentDate(LocalDate appointmentDate) {
        this.appointmentDate = appointmentDate;
    }

    public String getStatus() {
        return status;
    }

    public void setStatus(String status) {
        this.status = status;
    }
}

